import React, { useEffect, useMemo, useState } from 'react'
import { cultivationLogService, pondService } from '../../services/api'
import '../../styles/dashboard.css'
import '../../styles/manager/manager-common.css'
import '../../styles/manager/manager-cultivation-logs.css'

const formatVietnameseDateTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value

  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const formatVietnameseDate = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value

  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const ManagerCultivationLogs = () => {
  const [ponds, setPonds] = useState([])
  const [selectedPondId, setSelectedPondId] = useState('')
  const [logs, setLogs] = useState([])
  const [loading, setLoading] = useState(true)
  const [loadingLogs, setLoadingLogs] = useState(false)
  const [error, setError] = useState('')

  useEffect(() => {
    fetchPonds()
  }, [])

  useEffect(() => {
    if (!selectedPondId) {
      setLogs([])
      return
    }

    fetchLogs(selectedPondId)
  }, [selectedPondId])

  const fetchPonds = async () => {
    try {
      setLoading(true)
      const response = await pondService.getAllPonds()
      const pondList = response?.data?.data || []
      setPonds(pondList)
      if (pondList.length > 0) {
        setSelectedPondId(String(pondList[0].pond_id))
      }
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tải được danh sách ao nuôi')
    } finally {
      setLoading(false)
    }
  }

  const fetchLogs = async (pondId) => {
    try {
      setLoadingLogs(true)
      const response = await cultivationLogService.getByPondId(pondId)
      setLogs(response?.data?.data || [])
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tải được nhật ký xử lý')
      setLogs([])
    } finally {
      setLoadingLogs(false)
    }
  }

  const selectedPond = ponds.find((pond) => String(pond.pond_id) === String(selectedPondId))

  const summary = useMemo(() => {
    const total = logs.length
    return { total }
  }, [logs])

  if (loading) {
    return (
      <div className="dashboard-container manager-page">
        <div className="card">
          <div className="manager-cultivation-logs__loading">Đang tải danh sách ao nuôi...</div>
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard-container manager-page">
      <div className="manager-cultivation-logs__selector" style={{ marginBottom: '1rem' }}>
        <select
          className="input"
          value={selectedPondId}
          onChange={(e) => setSelectedPondId(e.target.value)}
        >
          <option value="">-- Chọn ao nuôi --</option>
          {ponds.map((pond) => (
            <option key={pond.pond_id} value={pond.pond_id}>
              {pond.pond_code} - {pond.pond_name}
            </option>
          ))}
        </select>
      </div>

      {error && <div className="alert alert-danger">{error}</div>}

      <div className="manager-cultivation-logs__summary-grid" style={{ display: 'flex', gap: '1rem', alignItems: 'stretch' }}>
        <div className="card" style={{ flex: '0 0 200px' }}>
          <h3>Tổng nhật ký</h3>
          <p className="manager-cultivation-logs__stat-value">{summary.total}</p>
        </div>
        <div className="card manager-cultivation-logs__info-card" style={{ flex: '1' }}>
          <h3>Thông tin ao đang xem</h3>
          <p className="manager-cultivation-logs__info-title">{selectedPond ? `${selectedPond.pond_code} - ${selectedPond.pond_name}` : 'Chưa chọn ao'}</p>
          <p className="manager-cultivation-logs__info-subtitle">{selectedPond ? `Mã ao: ${selectedPond.pond_code}` : '-'}</p>
        </div>
      </div>

      <div className="card">
        <h3>Danh sách nhật ký xử lý</h3>
        <div className="table-responsive">
          <table className="table">
            <thead>
              <tr>
                <th>Ngày xử lý</th>
                <th>Mùa vụ</th>
                <th>Nhân viên</th>
                <th>Đã làm gì</th>
                <th>Chi tiết</th>
                <th>Ghi lúc</th>
              </tr>
            </thead>
            <tbody>
              {loadingLogs ? (
                <tr>
                  <td colSpan="6">Đang tải...</td>
                </tr>
              ) : logs.length === 0 ? (
                <tr>
                  <td colSpan="6">Chưa có nhật ký xử lý nào</td>
                </tr>
              ) : (
                logs.map((log) => (
                  <tr key={log.log_id}>
                    <td>{formatVietnameseDate(log.log_date)}</td>
                    <td>{log.season_name || `Mùa vụ #${log.season_id}`}</td>
                    <td>{log.created_by_name || log.created_by_username || `#${log.created_by || '-'}`}</td>
                    <td>{log.action_type || '-'}</td>
                    <td className="manager-cultivation-logs__description">{log.description || '-'}</td>
                    <td>{formatVietnameseDateTime(log.created_at)}</td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}

export default ManagerCultivationLogs
